import { Player } from "../../objects/player";

const PlayerCard = (player : Player) => {     

    return(   
        <div className="col-sm-3">
            <div className="card">
                <div className="card-body">
                    <h5 className="card-title">{player.firstname} {player.surname} </h5>                    
                </div>
            </div>
        </div>        
    )
}
export default PlayerCard;
